+  const response = [
+    `${actionDescription} \u2192 capture #${captureNum}`,
+    `Size: ${actionResult.pageSize?.width}\xD7${actionResult.pageSize?.height}`,
+    `Snapshot: ${actionResult.captureDir}/`,
+    `Resources: page.html, page.md, screenshot.png, console-log.txt`
