+  const response = [
+    `${actionDescription} → capture #${captureNum}`,
+    `Size: ${actionResult.pageSize?.width}×${actionResult.pageSize?.height}`,
+    `Snapshot: ${actionResult.captureDir}/`,
+    `Resources: page.html, page.md, screenshot.png, console-log.txt`
